<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Sorting Algorithm Visualizer</title>
    <style>
        #bars {
            width: 100%;
            height: 300px;
            overflow-y: auto;
            border-bottom: 1px solid black;
        }

        .bar-container {
            display: flex;
            justify-content: space-between;
            margin: 10px 0;
        }

        .bar {
            width: 30px;
            height: 100%;
            background-color: #ddd;
            transition: height 0.3s ease;
        }

        @keyframes bar-height-up {
            from { height: 100%; }
            to { height: 200%; } // example: when fully sorted, the bars might be at a higher height? But note: the animation is infinite and will run until the array is sorted.
        }

        .bar-animated {
            animation: bar-height-up 1.5s infinite;
        }
    </style>
</head>
<body>
    <div id="bars"></div>
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>

    <script>
        // The window object is exposed for the API.
        window.viz = {
            array: [],          // -> current array of numbers
            setArray(a): {   // -> set the array (and redraw)
                const arr = [...a];  // copy the array
                // Update bars heights based on the values in the array.
                for (let i = 0; i < arr.length; i++) {
                    const bar = document.querySelector('.bar-container .bar');
                    if (i === 0) bar.style.height = arr[i] * 100 + 'px'; // example: height proportional to value
                }
                window.viz.array = arr;
            },
            sortStep(): {   // -> advance the sort ONE step; -> true when fully sorted
                let arr = window.viz.array;
                while (!window.viz.sorted()) {
                    const firstIndex = Math.floor(Math.random() * arr.length);
                    const secondIndex = Math.floor(Math.random() * arr.length);
                    if (arr[firstIndex] > arr[secondIndex]) {
                        // Swap the two elements
                        [arr[firstIndex], arr[secondIndex]] = [arr[secondIndex], arr[firstIndex]];
                        window.viz.setArray(arr);  // redraw because array changed
                    }
                }
            },
            sorted(): {   // -> boolean: is the array ascending?
                return arr.length > 0 && arr.every(x => x <= arr[0]);
            };
        };
    </script>
</body>
</html>
